import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const LeagueGeneration = () => {
    const [clasificacion, setClasificacion] = useState({});
    const [calendario, setCalendario] = useState({});
    const [equiposParaAsignar, setEquiposParaAsignar] = useState([]);
    const navigate = useNavigate();
    const clavesAscenso = [
        "ascensoDirecto_Liga2",
        "ascensoPlayoff_Liga2",
        "ascensoDirecto_PrimeraRFEF",
        "ascensoPlayoff_PrimeraRFEF",
        "ascensoDirecto_SegundaRFEF",
        "ascensoPlayoff_SegundaRFEF",
        "ascensoDirecto_TerceraRFEF",
        "ascensoPlayoff_TerceraRFEF"
      ];

      const nombresAscendidos = clavesAscenso.flatMap(clave =>
        JSON.parse(localStorage.getItem(clave) || "[]")
      );
    const mezclarEquipos = (equipos) => {
        const copia = [...equipos];
        for (let i = copia.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            [copia[i], copia[j]] = [copia[j], copia[i]];
        }
        return copia;
    };

    const agruparEquiposPorLiga = (equipos) => {
        return equipos.reduce((ligas, equipo) => {
            if (!ligas[equipo.liga]) ligas[equipo.liga] = [];
            ligas[equipo.liga].push(equipo);
            return ligas;
        }, {});
    };

    useEffect(() => {
        const generarLigas = async (esLigaPrimera = true) => {
            if(esLigaPrimera === true) {
                try {
                    const equiposAlmacenados = JSON.parse(localStorage.getItem("equipos")) || [];
    
                    if (!equiposAlmacenados.length) {
                        alert("El archivo de equipos está vacío.");
                        return;
                    }
    
                    const ligas = agruparEquiposPorLiga(equiposAlmacenados);
                    const clasificacionesPorLiga = {};
                    const calendariosPorLiga = {};
                    const descensosPorLigaTemp = {};
                    const ascensosPorLigaTemp = {};
                    const playoffsPorLigaTemp = {};
    
                    Object.entries(ligas).forEach(([liga, equiposLiga]) => {
                        const equiposAleatorios = mezclarEquipos(equiposLiga);
    
                        clasificacionesPorLiga[liga] = crearClasificacion(equiposAleatorios);
                        calendariosPorLiga[liga] = generarJornadasLiga(equiposAleatorios);
    
                        if (liga.includes("Primera RFEF")) {
                            descensosPorLigaTemp[liga] = 5;
                            ascensosPorLigaTemp[liga] = 1;
                            playoffsPorLigaTemp[liga] = 4;
                        } else if (liga.includes("Segunda RFEF")) {
                            descensosPorLigaTemp[liga] = 5;
                            ascensosPorLigaTemp[liga] = 1;
                            playoffsPorLigaTemp[liga] = 4;
                        } else if (liga.includes("Tercera RFEF")) {
                            descensosPorLigaTemp[liga] = 3;
                            ascensosPorLigaTemp[liga] = 1;
                            playoffsPorLigaTemp[liga] = 4;
                        } else if (liga === "La Liga") {
                            descensosPorLigaTemp[liga] = 3;
                        } else if (liga === "Liga 2") {
                            descensosPorLigaTemp[liga] = 4;
                            ascensosPorLigaTemp[liga] = 2;
                            playoffsPorLigaTemp[liga] = 4;
                        }
                    });
    
                    setClasificacion(clasificacionesPorLiga);
                    setCalendario(calendariosPorLiga);
    
                    localStorage.setItem("equipos", JSON.stringify(equiposAlmacenados));
                    localStorage.setItem("clasificacion", JSON.stringify(clasificacionesPorLiga));
                    localStorage.setItem("calendario", JSON.stringify(calendariosPorLiga));
                    localStorage.setItem("descensos", JSON.stringify(descensosPorLigaTemp));
                    localStorage.setItem("ascensos", JSON.stringify(ascensosPorLigaTemp));
                    localStorage.setItem("playoffs", JSON.stringify(playoffsPorLigaTemp));
    
                    console.log("Ligas generadas y almacenadas.");
                } catch (error) {
                    console.error("Error al cargar el JSON de equipos:", error);
                    alert("No se pudo cargar el archivo de equipos.");
                }
            } else {
                try {
                    const clasificaciones = JSON.parse(localStorage.getItem("clasificacion")) || {};
                    const ascensos = JSON.parse(localStorage.getItem("ascendidos_playoffs")) || {};
                    const equipos = JSON.parse(localStorage.getItem("equipos")) || [];
            
                    const asignables = [];
            
                    // Recolectar equipos que permanecen
                    for (const [liga, lista] of Object.entries(clasificaciones)) {
                        if (liga === "Liga 1") {
                            asignables.push(...lista.slice(0, -3)); // los que no descienden
                        } else if (liga === "Liga 2") {
                            asignables.push(...lista.slice(0, -4));
                        } else if (liga.includes("Primera RFEF")) {
                            asignables.push(...lista.slice(1, -10));
                        } else if (liga.includes("Segunda RFEF")) {
                            asignables.push(...lista.slice(1, -5));
                        } else if (liga.includes("Tercera RFEF")) {
                            asignables.push(...lista.slice(1)); // quitamos solo el 1º que asciende
                        }
                    }
            
                    // Recolectar descendidos
                    asignables.push(...clasificaciones["Liga 1"].slice(-3));
                    asignables.push(...clasificaciones["Liga 2"].slice(-4));
                    for (let i = 1; i <= 2; i++) {
                        asignables.push(...clasificaciones[`Primera RFEF - Grupo ${i}`].slice(-10));
                    }
                    for (let i = 1; i <= 5; i++) {
                        asignables.push(...clasificaciones[`Segunda RFEF - Grupo ${i}`].slice(-5));
                    }
            
                    // Recolectar ascendidos desde ascensos
                    for (const equiposAsc of Object.values(ascensos)) {
                        asignables.push(...equiposAsc);
                    }
            
                    // Recolectar otros necesarios (regionales para completar cupos)
                    const regionales = equipos.filter(e => e.liga.startsWith("Regionales"));
                    asignables.push(...regionales.slice(0, 40)); // solo si faltan más adelante
            
                    // Establecer en estado para que se muestre
                    setEquiposParaAsignar(asignables);
            
                    console.log("⚙️ Equipos para asignar manualmente:", asignables);
                    alert("Se han cargado todos los equipos para reorganizar. Asigna los grupos.");
                } catch (err) {
                    console.error("Error al reorganizar ligas:", err);
                }
            }
            
        }

        const flag = JSON.parse(localStorage.getItem("esLigaPrimera"));
        generarLigas(flag === null ? true : flag);
}, []);

    const crearClasificacion = (equipos) => {
        return equipos.map((equipo) => ({
            id: equipo.id,
            imagen: equipo.imagen,
            nombre: equipo.nombre,
            puntos: 0,
            partidosJugados: 0,
            victorias: 0,
            empates: 0,
            derrotas: 0,
            golesFavor: 0,
            golesContra: 0,
            diferenciaGoles: 0,
        }));
    };

    const generarJornadasLiga = (equipos) => {
        if (equipos.length % 2 !== 0) equipos.push({ id: -1, nombre: "Descanso" });
        const n = equipos.length;
        const mitad = n / 2;
        const jornadas = [];
        const rotacion = equipos.slice(1);

        for (let i = 0; i < n - 1; i++) {
            const jornada = [];
            const izquierda = [equipos[0], ...rotacion.slice(0, mitad - 1)];
            const derecha = rotacion.slice(mitad - 1).reverse();

            for (let j = 0; j < mitad; j++) {
                let local = i % 2 === 0 ? izquierda[j] : derecha[j];
                let visitante = i % 2 === 0 ? derecha[j] : izquierda[j];

                if (local.id !== -1 && visitante.id !== -1) {
                    jornada.push({ local, visitante });
                }
            }
            jornadas.push(jornada);
            rotacion.unshift(rotacion.pop());
        }

        const jornadasVuelta = jornadas.map(j =>
            j.map(({ local, visitante }) => ({
                local: visitante,
                visitante: local,
            }))
        );
        return [...jornadas, ...jornadasVuelta];
    };

    const handleContinue = () => {
        navigate("/main-menu");
    };

    return (
        <div className="league-generation">
            <h1>Ligas Generadas</h1>
            {Object.keys(clasificacion).map((liga) => (
                <div key={liga}>
                    <h2>{liga}</h2>
                </div>
            ))}
            <button onClick={handleContinue}>Continuar</button>
        </div>
    );
};

export default LeagueGeneration;
